constexpr size_t tdesign_21_count = 240;

// Get the appropriate t-design for a given ambisonics order.
// Returns a pointer to the data and sets count.
inline const float (*tdesign_for_order(int order, size_t& count))[3] {
    int t_needed = 2 * order + 1;
    if (t_needed <= 4) {
        count = tdesign_4_count;
        return tdesign_4_data;
    } else if (t_needed <= 6) {
        count = tdesign_6_count;
        return tdesign_6_data;
    } else if (t_needed <= 8) {
        count = tdesign_8_count;
        return tdesign_8_data;
    } else if (t_needed <= 10) {
        count = tdesign_10_count;
        return tdesign_10_data;
    } else if (t_needed <= 12) {
        count = tdesign_12_count;
        return tdesign_12_data;
    } else if (t_needed <= 14) {
        count = tdesign_14_count;
        return tdesign_14_data;
    } else if (t_needed <= 16) {
        count = tdesign_16_count;
        return tdesign_16_data;
    } else if (t_needed <= 18) {
        count = tdesign_18_count;
        return tdesign_18_data;
    } else if (t_needed <= 20) {
        count = tdesign_20_count;
        return tdesign_20_data;
    } else if (t_needed <= 21) {
        count = tdesign_21_count;
        return tdesign_21_data;
    } else {
        count = tdesign_21_count;
        return tdesign_21_data;
    }
}

